+
+@Service
+public class DashboardServiceImpl implements DashboardService {
+
+    private final AccountPayableRepository payableRepo;
+    private final AccountReceivableRepository receivableRepo;
+    private final TicketRepository ticketRepo;
+    private final ChatSessionRepository chatRepo;
+
+    public DashboardServiceImpl(AccountPayableRepository payableRepo,
+                                AccountReceivableRepository receivableRepo,
+                                TicketRepository ticketRepo,
+                                ChatSessionRepository chatRepo) {
+        this.payableRepo = payableRepo;
+        this.receivableRepo = receivableRepo;
+        this.ticketRepo = ticketRepo;
+        this.chatRepo = chatRepo;
+    }
+
+    @Override
+    public List<FinancePointDTO> financeSeries(int months) {
+        if (months <= 0) months = 6;
+        final YearMonth now = YearMonth.now();
+        List<FinancePointDTO> result = new ArrayList<>();
+        for (int i = months-1; i >= 0; i--) {
+            YearMonth ym = now.minusMonths(i);
+            LocalDate start = ym.atDay(1);
+            LocalDate end = ym.atEndOfMonth();
+            var rec = receivableRepo.findBetween(start, end);
+            var pay = payableRepo.findBetween(start, end);
+            BigDecimal sumRec = rec.stream().map(r -> r.getAmount()).reduce(BigDecimal.ZERO, BigDecimal::add);
+            BigDecimal sumPay = pay.stream().map(p -> p.getAmount()).reduce(BigDecimal.ZERO, BigDecimal::add);
+            result.add(new FinancePointDTO(ym.toString(), sumRec, sumPay));
+        }
+        return result;
+    }
+
+    @Override
+    public TicketStatusCountsDTO ticketStatusCounts() {
+        long open = ticketRepo.countByStatus(TicketStatus.OPEN);
+        long inProgress = ticketRepo.countByStatus(TicketStatus.IN_PROGRESS);
+        long closed = ticketRepo.countByStatus(TicketStatus.CLOSED);
+        return new TicketStatusCountsDTO(open, inProgress, closed);
+    }
+
+    @Override
+    public List<ChatsDailyPointDTO> chatsDaily(int days) {
+        if (days <= 0) days = 7;
+        LocalDate end = LocalDate.now();
+        LocalDate start = end.minusDays(days-1);
+        var list = chatRepo.findDailyBetween(start, end);
+        // Preencher buracos de dias sem registro
+        Map<LocalDate, Integer> map = new HashMap<>();
+        list.forEach(c -> map.put(c.getOpenedDate(), c.getOpenCount()));
+        List<ChatsDailyPointDTO> out = new ArrayList<>();
+        for (LocalDate d = start; !d.isAfter(end); d = d.plusDays(1)) {
+            out.add(new ChatsDailyPointDTO(d, map.getOrDefault(d, 0)));
+        }
+        return out;
+    }
