+        if (months <= 0) months = 6;
+        final YearMonth now = YearMonth.now();
+        List<FinancePointDTO> out = new ArrayList<>();
+        for (int i = months - 1; i >= 0; i--) {
+            YearMonth ym = now.minusMonths(i);
+            LocalDate start = ym.atDay(1);
+            LocalDate end = ym.atEndOfMonth();
+            BigDecimal rec = receberRepo.sumValorBetween(start, end, empresaId, parceiroId);
+            BigDecimal pay = pagarRepo.sumValorBetween(start, end, empresaId, parceiroId);
+            out.add(new FinancePointDTO(ym.toString(), rec, pay));
+        }
+        return out;
+    }
