+        var rows = chatRepo.countDailyByEmpresa(start, end, empresaId/*, parceiroId*/);
+        Map<LocalDate, Integer> map = new HashMap<>();
+        for (Object[] r: rows) {
+            LocalDate dia = (LocalDate) r[0];
+            Number qtd = (Number) r[1];
+            map.put(dia, qtd.intValue());
+        }
+        List<ChatsDailyPointDTO> out = new ArrayList<>();
+        for (LocalDate d = start; !d.isAfter(end); d = d.plusDays(1)) {
+            out.add(new ChatsDailyPointDTO(d, map.getOrDefault(d, 0)));
+        }
+        return out;
+    }
